"""File templates generated by ``reposhield connect``."""

from __future__ import annotations

import json
import os
from pathlib import Path
from typing import Any

from .profiles import SHIM_COMMANDS, IntegrationProfile


def dump_config(config: dict[str, Any]) -> str:
    try:
        import yaml

        return yaml.safe_dump(config, allow_unicode=True, sort_keys=False)
    except Exception:
        return json.dumps(config, ensure_ascii=False, indent=2) + "\n"


def load_config(path: str | Path) -> dict[str, Any]:
    text = Path(path).read_text(encoding="utf-8")
    try:
        import yaml

        data = yaml.safe_load(text)
    except Exception:
        data = json.loads(text)
    if not isinstance(data, dict):
        raise ValueError(f"invalid RepoShield config: {path}")
    return data


def render_agent_env(config: dict[str, Any]) -> str:
    gateway = config["gateway"]
    session = config["session"]
    return "\n".join(
        [
            "# Generated by reposhield connect.",
            f"export REPOSHIELD_REPO_ROOT={_sh_quote(config['repo_root'])}",
            f"export REPOSHIELD_MODE={_sh_quote(config['mode'])}",
            f"export REPOSHIELD_AGENT={_sh_quote(config['agent'])}",
            f"export REPOSHIELD_GATEWAY_BASE_URL={_sh_quote(gateway['base_url'])}",
            f"export OPENAI_BASE_URL={_sh_quote(gateway['base_url'])}",
            "export OPENAI_API_KEY='reposhield-local'",
            f"export REPOSHIELD_RUN_ID={_sh_quote(session['run_id'])}",
            f"export REPOSHIELD_CONVERSATION_ID={_sh_quote(session['conversation_id'])}",
            "export REPOSHIELD_REQUIRE_STABLE_SESSION_IDENTITY=1",
            "",
        ]
    )


def render_agent_instructions(config: dict[str, Any]) -> str:
    return "\n".join(
        [
            "# RepoShield Agent 接入说明",
            "",
            f"- 模式：`{config['mode']}`",
            f"- Agent：`{config['agent']}`",
            f"- 网关地址：`{config['gateway']['base_url']}`",
            "- API Key：`reposhield-local`",
            "",
            "多轮 agent 必须在每一轮请求中传入稳定身份：",
            "",
            "- `metadata.reposhield_run_id` 必须等于 `REPOSHIELD_RUN_ID`。",
            "- `metadata.conversation_id` 必须等于 `REPOSHIELD_CONVERSATION_ID`。",
            "- 如果使用 HTTP header，也可以传入 `X-RepoShield-Run-Id`，但请求 metadata 仍建议保留。",
            "",
            "不要为同一次任务的后续轮次重新生成 run_id / conversation_id，否则 RepoShield 无法把 PersistentSessionState 与 ActionGraph 连续起来。",
            "",
            "保护范围提示：Quick 主要保护模型边界；Standard 增加常见执行路径 shims；Full 增加 Studio、Approval API 与 demo 包。",
            "",
        ]
    )


def render_connect_readme(config: dict[str, Any]) -> str:
    lines = [
        "# RepoShield Connect",
        "",
        f"- Mode: `{config['mode']}`",
        f"- Agent: `{config['agent']}`",
        f"- Gateway: `{config['gateway']['base_url']}`",
        f"- AuditLog: `{config['audit']['path']}`",
        f"- SessionState: `{config['session']['state_path']}`",
        "",
        "## Next Steps",
        "",
        "```bash",
        "source .reposhield/agent.env",
        "reposhield start --repo .",
        "reposhield doctor --repo .",
        "```",
        "",
        "For Standard / Full mode, put shims before system paths:",
        "",
        "```bash",
        'export PATH="$(pwd)/.reposhield/shims:$PATH"',
        "```",
        "",
        "Every multi-turn agent request must include stable `metadata.reposhield_run_id` and `metadata.conversation_id`.",
        "",
    ]
    return "\n".join(lines)


def render_gateway_script(config: dict[str, Any], suffix: str) -> str:
    python_cmd = _python_invocation()
    repo = config["repo_root"]
    gateway = config["gateway"]
    audit = config["audit"]["path"]
    policy_mode = config["policy"]["mode"]
    sh_extra = ""
    ps_extra = ""
    if gateway.get("upstream_base_url"):
        sh_extra += f" --upstream-base-url {_sh_quote(gateway['upstream_base_url'])}"
        ps_extra += f" --upstream-base-url {_ps_quote(gateway['upstream_base_url'])}"
    if config["policy"].get("pack"):
        sh_extra += f" --policy-config {_sh_quote(config['policy']['pack'])}"
        ps_extra += f" --policy-config {_ps_quote(config['policy']['pack'])}"
    if suffix == ".ps1":
        return (
            f"& {python_cmd} -m reposhield.cli gateway-start --repo {_ps_quote(repo)} "
            f"--host {gateway['host']} --port {gateway['port']} --audit {_ps_quote(audit)} --policy-mode {policy_mode}{ps_extra}\n"
        )
    return (
        "#!/usr/bin/env sh\n"
        "set -eu\n"
        f"exec {python_cmd} -m reposhield.cli gateway-start --repo {_sh_quote(repo)} "
        f"--host {gateway['host']} --port {gateway['port']} --audit {_sh_quote(audit)} --policy-mode {policy_mode}{sh_extra}\n"
    )


